import os
import secrets
import time
from functools import wraps
from flask import Flask, request, jsonify, session, redirect, url_for
from werkzeug.security import generate_password_hash, check_password_hash
import pyotp

app = Flask(__name__)
app.secret_key = os.environ.get('SECRET_KEY', secrets.token_hex(32))
app.config['SESSION_COOKIE_HTTPONLY'] = True
app.config['SESSION_COOKIE_SAMESITE'] = 'Lax'
app.config['SESSION_COOKIE_SECURE'] = True
app.config['PERMANENT_SESSION_LIFETIME'] = 1800

users_db = {
    'user1': {
        'password_hash': generate_password_hash('password123'),
        'mfa_secret': pyotp.random_base32(),
        'mfa_enabled': True
    },
    'user2': {
        'password_hash': generate_password_hash('password456'),
        'mfa_secret': pyotp.random_base32(),
        'mfa_enabled': True
    }
}

mfa_pending = {}

def require_auth(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if 'username' not in session:
            return jsonify({'error': 'Authentication required'}), 401
        
        if not session.get('mfa_verified', False):
            return jsonify({'error': 'MFA verification required'}), 403
        
        return f(*args, **kwargs)
    return decorated_function

def require_password_only(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if 'username' not in session:
            return jsonify({'error': 'Authentication required'}), 401
        
        return f(*args, **kwargs)
    return decorated_function

@app.route('/login', methods=['POST'])
def login():
    data = request.get_json()
    username = data.get('username')
    password = data.get('password')
    
    if not username or not password:
        return jsonify({'error': 'Username and password required'}), 400
    
    user = users_db.get(username)
    if not user or not check_password_hash(user['password_hash'], password):
        return jsonify({'error': 'Invalid credentials'}), 401
    
    session.clear()
    session['username'] = username
    session['mfa_verified'] = False
    session['login_time'] = time.time()
    session.permanent = True
    
    if user.get('mfa_enabled', False):
        mfa_token = secrets.token_urlsafe(32)
        mfa_pending[mfa_token] = {
            'username': username,
            'timestamp': time.time()
        }
        
        return jsonify({
            'message': 'Password verified',
            'mfa_required': True,
            'mfa_token': mfa_token,
            'redirect': '/verify-mfa'
        }), 200
    else:
        session['mfa_verified'] = True
        return jsonify({
            'message': 'Login successful',
            'mfa_required': False
        }), 200

@app.route('/verify-mfa', methods=['POST'])
def verify_mfa():
    data = request.get_json()
    mfa_code = data.get('mfa_code')
    mfa_token = data.get('mfa_token')
    
    if 'username' not in session:
        return jsonify({'error': 'Not authenticated'}), 401
    
    if session.get('mfa_verified', False):
        return jsonify({'message': 'MFA already verified'}), 200
    
    if not mfa_token or mfa_token not in mfa_pending:
        return jsonify({'error': 'Invalid MFA token'}), 400
    
    pending_data = mfa_pending[mfa_token]
    
    if pending_data['username'] != session['username']:
        return jsonify({'error': 'MFA token mismatch'}), 403
    
    if time.time() - pending_data['timestamp'] > 300:
        del mfa_pending[mfa_token]
        return jsonify({'error': 'MFA token expired'}), 400
    
    if not mfa_code:
        return jsonify({'error': 'MFA code required'}), 400
    
    username = session['username']
    user = users_db.get(username)
    
    if not user:
        return jsonify({'error': 'User not found'}), 404
    
    totp = pyotp.TOTP(user['mfa_secret'])
    
    if totp.verify(mfa_code, valid_window=1):
        session['mfa_verified'] = True
        session['mfa_verified_time'] = time.time()
        del mfa_pending[mfa_token]
        
        return jsonify({'message': 'MFA verification successful'}), 200
    else:
        return jsonify({'error': 'Invalid MFA code'}), 401

@app.route('/protected', methods=['GET'])
@require_auth
def protected_resource():
    return jsonify({
        'message': 'Access granted to protected resource',
        'username': session['username']
    }), 200

@app.route('/semi-protected', methods=['GET'])
@require_password_only
def semi_protected_resource():
    mfa_status = 'verified' if session.get('mfa_verified', False) else 'pending'
    
    return jsonify({
        'message': 'Access granted with password authentication',
        'username': session['username'],
        'mfa_status': mfa_status,
        'warning': 'Full access requires MFA verification' if not session.get('mfa_verified', False) else None
    }), 200

@app.route('/logout', methods=['POST'])
def logout():
    username = session.get('username')
    session.clear()
    return jsonify({'message': 'Logged out successfully'}), 200

@app.route('/mfa-setup', methods=['GET'])
@require_password_only
def mfa_setup():
    username = session['username']
    user = users_db.get(username)
    
    if not user:
        return jsonify({'error': 'User not found'}), 404
    
    secret = user['mfa_secret']
    totp = pyotp.TOTP(secret)
    provisioning_uri = totp.provisioning_uri(username, issuer_name="SecureApp")
    
    return jsonify({
        'secret': secret,
        'provisioning_uri': provisioning_uri,
        'qr_code_data': provisioning_uri
    }), 200

@app.route('/status', methods=['GET'])
def status():
    if 'username' not in session:
        return jsonify({'authenticated': False}), 200
    
    return jsonify({
        'authenticated': True,
        'username': session['username'],
        'mfa_verified': session.get('mfa_verified', False),
        'session_age': time.time() - session.get('login_time', time.time())
    }), 200

@app.before_request
def cleanup_expired_mfa_tokens():
    current_time = time.time()
    expired_tokens = [token for token, data in mfa_pending.items() 
                     if current_time - data['timestamp'] > 300]
    for token in expired_tokens:
        del mfa_pending[token]

if __name__ == '__main__':
    app.run(debug=False, host='127.0.0.1', port=5000)